"""
MABE Bootstrap: 6PPD-Q Full Pipeline + DNA Origami Tertiary Binding

Complete small-molecule guest design pipeline:
  SMILES -> pharmacophore -> pocket spec -> host screening
       -> selectivity screening -> MIP design -> de novo receptors
       -> DNA origami tertiary binding (ATHENA/pyDAEDALUS interface)

New modules:
  core/small_molecule_target.py   - Guest pharmacophore + pocket spec + host screening
  core/selectivity_screen.py      - Target vs interferent panel, per-host ratios
  core/dna_origami_pocket.py      - Tertiary binding: pocket spec -> modules -> cage -> staple placement
  core/athena_interface.py         - ATHENA/pyDAEDALUS translation layer (PLY, JSON, spec mode)
  adapters/mip_adapter.py         - MIP monomer selection + synthesis protocol
  tests/test_6ppd_q.py            - 75 integration tests

Modified modules:
  core/unified_scorer_v2.py          - CB portal restriction penalty
  core/physics_realization_bridge.py  - design_for_guest() with all pipeline steps
  core/de_novo_generator.py           - 16 receptor backbones + generate_for_guest()

Test results: 75 passed (6PPD-Q), 25 passed (regression), 0 failed

Prereqs: F0-F3 complete
"""
import base64, pathlib

FILES = {
    "core/small_molecule_target.py": "",
    "core/selectivity_screen.py": "",
    "core/dna_origami_pocket.py": "",
    "core/athena_interface.py": "",
    "core/unified_scorer_v2.py": "",
    "adapters/mip_adapter.py": "",
    "tests/test_6ppd_q.py": "",
    "core/physics_realization_bridge.py": "",
    "core/de_novo_generator.py": "",
}


def apply():
    root = pathlib.Path(__file__).resolve().parent
    for rel_path, b64_content in FILES.items():
        target = root / rel_path
        target.parent.mkdir(parents=True, exist_ok=True)
        content = base64.b64decode(b64_content)
        target.write_bytes(content)
        print(f"  wrote {rel_path} ({len(content):,} bytes)")
    print(f"\n  {len(FILES)} files written.")


if __name__ == "__main__":
    print("=" * 70)
    print("MABE Bootstrap: 6PPD-Q + DNA Origami Tertiary Binding")
    print("=" * 70)
    apply()
    print("\nRun tests:  python -m pytest tests/test_6ppd_q.py -v")